parameters.jsCode:
const raw = $input.item.json.text || '';

const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const parsed = JSON.parse(cleaned);

return {
  priority:         parsed.priority,
  summary:          parsed.summary,
  suggested_action: parsed.suggested_action,
  from:             $('Mail Content Structure').item.json.name,
  email:            $('Mail Content Structure').item.json.from,
  subject:          $('Mail Content Structure').item.json.subject
};

// 1. Get AI raw response
const raw = $json.output?.[0]?.content?.[0]?.text || "{}";

// 2. Clean markdown if present
const cleaned = raw.replace(/```json|```/g, "").trim();

let aiData;

// 3. Safe JSON parsing
try {
  aiData = JSON.parse(cleaned);
} catch (e) {
  aiData = {
    category: "Unknown",
    priority: "Medium",
    summary: "AI response parsing failed"
  };
}

// 4. Get original email safely
const original = $items("Mail Content Structure")?.[0]?.json || {};

// 5. Override priority logic (safe)
if (
  original?.subject?.toLowerCase()?.includes("urgent") ||
  original?.body?.toLowerCase()?.includes("asap")
) {
  aiData.priority = "High";
}

// 6. Merge everything
return [
  {
    json: {
      ...original,
      ...aiData
    }
  }
];

