parameters.jsCode:
// 1. Get raw AI response
const reply = $json.output?.[0]?.content?.[0]?.text || "";

// 2. Get original email
const original = $items("Mail Content Structure")?.[0]?.json || {};

// 3. Extract subject
let subject = original.subject || "Your Email";

const subjectMatch = reply.match(/Subject:(.*)/i);
if (subjectMatch) {
  subject = subjectMatch[1].trim();
}

// 4. Clean body (remove Subject line if present)
let body = reply.replace(/Subject:.*\n/i, "").trim();

// 5. Add signature
body = body
  .replace(/\n{3,}/g, "\n\n") // clean extra spacing
  .trim() + "\n\n--\nMy Assistance";

// 6. Final output
return [
  {
    json: {
      to: original.from,
      subject: "Re: " + subject,
      body: body
    }
  }
];

